INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('24e555f2-21a9-52cc-8290-fa7cf036d024', '1ac164f6-5c44-46da-8f26-0c1404a97e0e', 'The new fabric is designed to ___ moisture quickly, keeping the athlete comfortable during intense workouts.', '這種新布料旨在快速吸收水分，讓運動員在劇烈運動期間保持舒適。', 'absorb', 'reject', 'produce', 'release', '詞根 ab- 表示「離開/從...」，sorb 表示「吸」，合起來就是「吸入」。', '想像一個吸塵器把灰塵「吸」走，absorb 就是把液體或能量「吸」進去的動作。', '2026-07-06 16:15:28', '2026-07-06 16:15:28'),
('2b972d17-8571-561c-9759-dd0d7b4545cc', '77d47914-1485-4a40-86d7-6fe34e6e1f19', 'A gold necklace is a common ___ used to enhance a simple dress.', '金項鍊是常用來增添素色洋裝美感的配件。', 'accessory', 'obstacle', 'miracle', 'habit', 'access (接近) + -ory (表示「與...有關的人或物」的字尾) → 附加的配件。', '想像配件是為了讓原本的東西更好用或更美觀而「附加」在旁邊的東西。', '2026-07-06 16:44:50', '2026-07-06 16:44:50'),
('71a48089-b6ca-5849-b603-e66afdec8c04', '1ae6bc0e-3f92-4b79-a051-77bf606b6020', 'The hotel requires an ___ fee for guests who want to check out late.', '對於想要延遲退房的房客，飯店會收取一筆額外的費用。', 'additional', 'annual', 'initial', 'external', 'ad (向/去) + dit (給予) + ion (名詞字尾) + al (形容詞字尾) → 原意為「被加給的」，引申為額外的。', 'add (增加) + itional → 增加出來的 → 額外的。', '2026-07-06 17:40:20', '2026-07-06 17:40:20'),
('a80ce172-9ac6-5ad3-8961-8cd49028e0b4', '0248abfe-fdbd-422f-b02b-7f57f38c9922', 'Due to the heavy traffic in the city, the ___ has become increasingly polluted.', '由於市內的交通繁忙，空氣變得越來越髒污。', 'air', 'water', 'soil', 'light', 'air 為名詞，指大氣或空氣。', '想像在戶外呼吸新鮮的 air (空氣)。', '2026-07-06 19:27:39', '2026-07-06 19:27:39'),
('76331fe8-ff90-5a90-9ed3-00c67728bab8', 'da363fcf-df61-4483-9432-5ab5951d1756', 'The professor used an ___ between a cell and a factory to explain how biological processes work.', '教授利用細胞與工廠之間的類比，來解釋生物程序是如何運作的。', 'analogy', 'argument', 'illusion', 'obstacle', 'ana- (根據) + logy (比例/說話/理據) → 根據比例或理據進行的比較，即「類比」。', 'analog (類比的) → analogy (類比)。記住 analog 與 analogy 是同源詞，看到 analog 就聯想到 analogy。', '2026-07-06 21:01:56', '2026-07-06 21:01:56'),
('ba8e604f-9853-5f1e-bb56-d9143358ae50', '2148b226-a44f-453e-ac23-6e310525b3c4', 'She likes to study English ___ Chinese in her free time.', '她在空閒時間喜歡學習英文和中文。', 'and', 'but', 'or', 'so', '連接詞，用於連接兩個對等的成分。', 'A + B = A and B', '2026-07-05 09:37:28', '2026-07-05 09:37:28'),
('a6962e87-f2b4-5ea7-8ca1-2581cd4b9a8c', 'f7e2225d-0539-4f5a-8fc3-144d18d6716d', 'The company''s most valuable ___ is its team of creative designers.', '這間公司最寶貴的資產就是其創意設計師團隊。', 'asset', 'burden', 'obstacle', 'debt', 'asset 原意指「足以應付的財產」，在商業或個人情境中，指能帶來利益的資產或優勢。', '看到 asset → 聯想 valuable (有價值的) 東西被 set (放置) 在你的財產清單中。', '2026-07-07 01:01:20', '2026-07-07 01:01:20'),
('0bc5efe7-e966-509c-ad9a-b074a7deb8f0', '091ec2df-d3e4-4445-aa17-4813e48e84b3', 'After playing in the mud, the dog needs to ___ to get clean.', '在泥巴裡玩耍過後，這隻狗需要洗澡才能變乾淨。', 'bathe', 'sleep', 'eat', 'dance', 'bathe 的字根是 bath (洗澡/浴缸)。', 'b-a-t-h-e → 想像在 bath (浴缸) 裡洗澡。', '2026-07-07 02:39:34', '2026-07-07 02:39:34'),
('7f5dedd9-6773-5796-9912-7655f9119c74', '6fa36aac-5b95-4a49-aa9e-e09930a7c057', 'He ___ a teacher in our school.', '他是我們學校的一位老師。', 'is', 'has', 'likes', 'wants', 'be 為連綴動詞，用來表達身份或狀態。', 'be 是萬能動詞，主詞不同，形式跟著變。', '2026-07-05 12:55:22', '2026-07-05 12:55:22'),
('fd9515e3-7c28-5c94-8fd1-34a68b3f7328', '0c540794-c18e-48dc-964e-63a65a1ec1ee', 'The cat is sleeping ___ the two pillows.', '這隻貓睡在兩個枕頭之間。', 'between', 'among', 'under', 'beside', 'be- (在...之間) + tween (兩者之中) → 用於兩個物體之間。', '看到 two (兩個) 就要聯想到 between。', '2026-07-05 07:06:19', '2026-07-05 07:06:19'),
('6db39c13-4a4e-5ec9-831d-5ca03d094384', '6ec9d89b-3d8c-4cdc-9b87-122015df1097', 'The ___ has two wheels and a seat.', '這輛腳踏車有兩個輪子和一個座墊。', 'bicycle', 'car', 'bus', 'plane', 'bi- (二) + cycle (輪圈) → 腳踏車。', 'bi- 代表 2，cycle 是圓圈，兩個圓圈就是腳踏車！', '2026-07-07 03:35:41', '2026-07-07 03:35:41'),
('1fac687f-6fe9-55bd-ac84-e637c455d218', '34362c63-2e2f-4d07-b79d-9fee47a767f9', 'We often go to the ___ on Sundays.', '我們常在星期天去教堂。', 'church', 'school', 'park', 'market', 'church 為名詞，指教堂。', 'Sunday (星期日) → church (教堂)。', '2026-07-07 03:59:41', '2026-07-07 03:59:41'),
('ce08c8f4-415d-52c5-946a-7fdd10263b24', 'f2cf9616-eb69-4560-b2a3-434ee352bc7e', 'Please ___ your homework before you go to bed.', '請在睡覺前完成你的功課。', 'complete', 'enjoy', 'borrow', 'forget', 'com (一起/完全) + plete (填滿) → 全部填滿 → 完成、完整的。', '想像把拼圖全部填滿 (plete) 起來，就是完整的 (complete) 了。', '2026-07-07 09:16:01', '2026-07-07 09:16:01'),
('88e0855a-ffda-5f34-a844-f2885fef9600', 'cd27aab0-de60-4464-ba48-418a869eafe9', 'We usually ___ dinner at home.', '我們通常在家吃晚餐。', 'eat', 'walk', 'read', 'watch', '此為基礎動詞，無特定字根。', 'Dinner (晚餐) → 搭配 eat (吃)。', '2026-07-07 03:11:34', '2026-07-07 03:11:34'),
('d783c059-05c9-544d-9e74-238bcdf3c2d4', '4a8ddddb-14e6-4832-8c00-be36c125cd16', 'He visits his grandparents ___ month.', '他每個月都會去探望他的祖父母。', 'every', 'many', 'few', 'much', '表示「每一個」，後面接單數名詞。', 'Every + 單數名詞 → 用來表達規律的動作。', '2026-07-07 04:28:27', '2026-07-07 04:28:27'),
('4404792a-e6af-5c33-8b43-935a33e9f31c', '4c7bf4a2-cdaa-4597-b8ab-ccf11ab3e97a', 'I bought a special gift ___ my mother.', '我為我母親買了一份特別的禮物。', 'for', 'with', 'at', 'by', '介係詞，表示對象', '送禮物給某人時，對象用 for', '2026-07-05 08:40:54', '2026-07-05 08:40:54'),
('a7b4e5e3-ac8d-595b-920a-de17b6f96408', '83a6c60d-263f-41f2-ba17-afeb8e5d6d81', '___ are many reasons to protect the environment.', '有許多理由說明我們應該保護環境。', 'There', 'When', 'Why', 'How', 'There 在句首常用於 There is/are 句型，表示「存在」某物。', 'There are... 是一個常用句型，用來介紹某處「有」什麼東西。', '2026-07-06 11:01:36', '2026-07-06 11:01:36');
